/* eslint-disable quotes */
/* eslint-disable no-console */

/**
 * @param {boolean} condition
 * @param {string} message
 * @param {string} [type]
 */
const print = (condition, message, type = 'error') => {
  if (condition) {
    return;
  }
  if (typeof console !== 'undefined') {
    let logFunction = /** @type {function | undefined} */ (console[/** @type {keyof typeof console} */(type)]);
    if (typeof logFunction !== 'function') logFunction = console.error;
    logFunction(message);
  }
  try {
    throw new Error(message);
  // eslint-disable-next-line no-empty
  } catch (x) {}
};

const warning = process.env.NODE_ENV !== "'production'" && process.env.NODE_ENV !== "production" ? print : () => {};

export default warning;
